  /**
   * SkillIcons - 技能 SVG 图标生成器
   * 使用方式: SkillIcons.icon('主动', '基础') 或 SkillIcons.icon('召唤', '进阶', 'extra-class')
   */
  const SkillIcons = {
    /**
     * 生成技能 SVG 图标 HTML
     * @param {string} type - 技能类型 ('主动', '召唤', '特殊', '职业特殊')
     * @param {string} tier - 技能阶位 ('基础'-'奥义', '觉醒一'-'觉醒三')
     * @param {string} extraClass - 额外的 CSS 类名
     * @returns {string} - SVG HTML 字符串
     */
    icon: function (type, tier, extraClass = '') {
      // 规范化类型
      let mainType = '主动';
      if (type === '召唤') mainType = '召唤';
      else if (type === '特殊' || type === '被动' || type === '辅助') mainType = '特殊';
      else if (type === '职业特殊') mainType = '职业特殊';

      // 获取路径数据
      let pathData = '';
      if (mainType === '职业特殊') {
        pathData = SKILL_SVG_PATHS['职业特殊'] || '';
      } else {
        const tierKey = tier || '基础';
        pathData = SKILL_SVG_PATHS[mainType]?.[tierKey] || '';
      }

      const isEmpty = !pathData;
      const classes = ['skill-icon-svg', extraClass].filter(Boolean).join(' ');
      const opacity = isEmpty ? '0.3' : '1';

      // 如果路径为空，使用默认占位符
      const finalPath = pathData || DEFAULT_SVG_PATH;

      return `<svg class="${classes}" viewBox="0 0 512 512" xmlns="http://www.w3.org/2000/svg" aria-hidden="true" style="opacity:${opacity}"><path fill="currentColor" d="${finalPath}"/></svg>`;
    },

    /**
     * 检查技能图标是否已配置 SVG 路径
     * @param {string} type - 技能类型
     * @param {string} tier - 技能阶位
     * @returns {boolean}
     */
    hasIcon: function (type, tier) {
      if (type === '职业特殊') {
        return !!SKILL_SVG_PATHS['职业特殊'];
      }
      let mainType = '主动';
      if (type === '召唤') mainType = '召唤';
      else if (type === '特殊' || type === '被动' || type === '辅助') mainType = '特殊';
      return !!SKILL_SVG_PATHS[mainType]?.[tier || '基础'];
    },

    /**
     * 获取所有未配置的技能图标列表 (用于调试)
     * @returns {string[]}
     */
    getMissingIcons: function () {
      const missing = [];
      ['主动', '召唤', '特殊'].forEach(type => {
        ['基础', '转职', '进阶', '必杀', '奥义', '觉醒一', '觉醒二', '觉醒三'].forEach(tier => {
          if (!SKILL_SVG_PATHS[type]?.[tier]) {
            missing.push(`${type}-${tier}`);
          }
        });
      });
      if (!SKILL_SVG_PATHS['职业特殊']) {
        missing.push('职业特殊');
      }
      return missing;
    }
  };

