  /**
   * 将 Mock 数据写入 MVU 系统
   */
  const injectMockDataToMvu = async () => {
    if (!mvuState.ready && !mvuState.check()) {
      showToast('error', 'MVU系统不可用，无法写入Mock数据');
      return false;
    }
    try {
      let mvuData = mvuState.mvu.getMvuData({ type: 'message', message_id: 'latest' });
      if (!mvuData) {
        mvuData = { stat_data: {} };
      }
      if (!mvuData.stat_data) {
        mvuData.stat_data = {};
      }

      // 深拷贝 mock 数据，构建完整的 stat_data
      const mockCopy = JSON.parse(JSON.stringify(MOCK_ALL_DATA));

      // 将 mock 中的技能树结构提升到人物下
      mvuData.stat_data.人物 = {
        名称: '鬼泣剑士',
        种族: '巨人种',
        职业: '鬼泣',
        等级: 45,
        当前总经验: 3200,
        升级阈值: 5000,
        生命值上限: 4825,
        当前生命值: 3860,
        SP: 200,
        AC: 18,
        CP: 50,
        RP: 12,
        战斗属性: { 暴击率: 5, 暴击伤害: 1.2, 暴击阈值: 12, 物理减伤: 3, 魔法减伤: 0 },
        属性: { 力量: 16, 敏捷: 12, 体质: 18, 智力: 14, 感知: 10, 魅力: 8, 属性点: 3 },
        技能树: mockCopy.人物.技能树,
        主动技能槽: mockCopy.人物.主动技能槽 || {},
        觉醒技能槽: mockCopy.人物.觉醒技能槽 || {},
        连携奥义槽: mockCopy.人物.连携奥义槽 || {},
        状态效果: mockCopy.人物.状态效果 || {},
        背包: mockCopy.人物.背包,
        装备列表: mockCopy.人物.装备列表
      };
      mvuData.stat_data.世界信息 = mockCopy.世界信息;
      mvuData.stat_data.任务列表 = mockCopy.任务列表;
      mvuData.stat_data.种族棋子收藏 = mockCopy.种族棋子收藏;
      mvuData.stat_data.战斗 = mockCopy.战斗;
      mvuData.stat_data.羁绊列表 = mockCopy.羁绊列表;
      mvuData.stat_data.人物.声望 = mockCopy.声望;
      mvuData.stat_data.传闻 = mockCopy.传闻;
      mvuData.stat_data.附近的人 = mockCopy.附近的人;

      await enqueueMvuWrite(async () => {
        await mvuState.mvu.replaceMvuData(mvuData, { type: 'message', message_id: 'latest' });
        return true;
      });
      log.info('Mock数据已写入MVU系统');
      showToast('success', 'Mock数据已写入MVU');
      return true;
    } catch (e) {
      log.error('写入Mock数据失败:', e);
      showToast('error', '写入失败: ' + (e.message || '未知错误'));
      return false;
    }
  };

