  // 生成八角星路径 - 完全复用AppleStyle-Star的算法
  const getOctagramPath = (R, rotationOffsetDeg = 0) => {
    let d = "M ";
    let N = 8;
    let K = 3;
    let offsetRad = rotationOffsetDeg * Math.PI / 180;
    let cx = 50;
    let cy = 50;
    for (let i = 0; i <= N; i++) {
      let idx = (i * K) % N;
      let angle = (idx * 2 * Math.PI / N) - Math.PI / 2 + offsetRad;
      let x = cx + Math.cos(angle) * R;
      let y = cy + Math.sin(angle) * R;
      if (i === 0) d += x.toFixed(2) + "," + y.toFixed(2) + " ";
      else d += "L " + x.toFixed(2) + "," + y.toFixed(2) + " ";
    }
    d += "Z";
    return d;
  };

